import React, { useState } from 'react';
import { RESOURCES, TYPE_LABELS, STATUS_LABELS } from '../../data/mockData';
import { PageHeader, SearchBar, FilterChips, Card, StatusBadge, Btn, Modal, Field, Input, Select, Textarea, Table, Tr, Td, EmptyState } from '../../components/UI';
import { useToast } from '../../utils/useToast';
import { Toast } from '../../components/UI';

const TYPE_OPTS = [
  { value: 'all', label: 'Todos' },
  { value: 'salon', label: 'Salones' },
  { value: 'lab', label: 'Laboratorios' },
  { value: 'equipment', label: 'Equipos' },
];
const STATUS_OPTS = [
  { value: 'all', label: 'Todos' },
  { value: 'available', label: 'Disponible' },
  { value: 'reserved', label: 'Reservado' },
  { value: 'loaned', label: 'Prestado' },
  { value: 'maintenance', label: 'Mantenimiento' },
];

export default function AdminResources() {
  const [resources, setResources] = useState(RESOURCES);
  const [search, setSearch] = useState('');
  const [typeFilter, setTypeFilter] = useState('all');
  const [statusFilter, setStatusFilter] = useState('all');
  const [modalOpen, setModalOpen] = useState(false);
  const [editTarget, setEditTarget] = useState(null);
  const [form, setForm] = useState({ name: '', type: 'salon', location: '', capacity: '', description: '', status: 'available' });
  const { toast, showToast } = useToast();

  const filtered = resources.filter(r => {
    const matchSearch = r.name.toLowerCase().includes(search.toLowerCase()) || r.location.toLowerCase().includes(search.toLowerCase());
    const matchType = typeFilter === 'all' || r.type === typeFilter;
    const matchStatus = statusFilter === 'all' || r.status === statusFilter;
    return matchSearch && matchType && matchStatus;
  });

  function openNew() {
    setEditTarget(null);
    setForm({ name: '', type: 'salon', location: '', capacity: '', description: '', status: 'available' });
    setModalOpen(true);
  }

  function openEdit(r) {
    setEditTarget(r);
    setForm({ name: r.name, type: r.type, location: r.location, capacity: r.capacity || '', description: r.description, status: r.status });
    setModalOpen(true);
  }

  function handleSave() {
    if (!form.name || !form.location) return showToast('Completa los campos requeridos', 'error');
    if (editTarget) {
      setResources(prev => prev.map(r => r.id === editTarget.id ? { ...r, ...form } : r));
      showToast('Recurso actualizado');
    } else {
      const newR = { id: `r${Date.now()}`, ...form, capacity: form.capacity ? Number(form.capacity) : null };
      setResources(prev => [...prev, newR]);
      showToast('Recurso creado exitosamente');
    }
    setModalOpen(false);
  }

  function handleDelete(id) {
    setResources(prev => prev.filter(r => r.id !== id));
    showToast('Recurso eliminado', 'info');
  }

  return (
    <div>
      <PageHeader
        title="Recursos institucionales"
        subtitle={`${resources.length} recursos registrados`}
        action={<Btn variant="primary" onClick={openNew}>+ Nuevo recurso</Btn>}
      />

      {/* Filters */}
      <Card style={{ padding: '14px 16px', marginBottom: '16px', display: 'flex', gap: '16px', alignItems: 'center', flexWrap: 'wrap' }}>
        <SearchBar value={search} onChange={setSearch} placeholder="Buscar recurso..." />
        <FilterChips options={TYPE_OPTS} value={typeFilter} onChange={setTypeFilter} />
        <FilterChips options={STATUS_OPTS} value={statusFilter} onChange={setStatusFilter} />
        <span style={{ marginLeft: 'auto', fontSize: '12px', color: 'var(--text-tertiary)' }}>{filtered.length} resultado{filtered.length !== 1 ? 's' : ''}</span>
      </Card>

      {/* Table */}
      <Card>
        {filtered.length === 0
          ? <EmptyState icon="📦" title="Sin resultados" subtitle="Ajusta los filtros o crea un nuevo recurso." />
          : (
            <Table headers={['Recurso', 'Tipo', 'Ubicación', 'Capacidad', 'Estado', 'Acciones']}>
              {filtered.map(r => (
                <Tr key={r.id}>
                  <Td>
                    <div style={{ fontWeight: 500 }}>{r.name}</div>
                    <div style={{ fontSize: '12px', color: 'var(--text-tertiary)', marginTop: '1px' }}>{r.description}</div>
                  </Td>
                  <Td><span style={{ fontSize: '12px', color: 'var(--text-secondary)' }}>{TYPE_LABELS[r.type]}</span></Td>
                  <Td style={{ color: 'var(--text-secondary)' }}>{r.location}</Td>
                  <Td style={{ color: 'var(--text-secondary)' }}>{r.capacity ? `${r.capacity} pers.` : '—'}</Td>
                  <Td><StatusBadge status={r.status} /></Td>
                  <Td>
                    <div style={{ display: 'flex', gap: '6px' }}>
                      <Btn size="sm" onClick={() => openEdit(r)}>Editar</Btn>
                      <Btn size="sm" variant="danger" onClick={() => handleDelete(r.id)}>Eliminar</Btn>
                    </div>
                  </Td>
                </Tr>
              ))}
            </Table>
          )}
      </Card>

      {/* Modal */}
      <Modal
        open={modalOpen}
        onClose={() => setModalOpen(false)}
        title={editTarget ? 'Editar recurso' : 'Nuevo recurso'}
        footer={<>
          <Btn onClick={() => setModalOpen(false)}>Cancelar</Btn>
          <Btn variant="primary" onClick={handleSave}>{editTarget ? 'Guardar cambios' : 'Crear recurso'}</Btn>
        </>}
      >
        <Field label="Nombre *">
          <Input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} placeholder="Ej: Salón 101" />
        </Field>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
          <Field label="Tipo">
            <Select value={form.type} onChange={e => setForm(f => ({ ...f, type: e.target.value }))}>
              <option value="salon">Salón</option>
              <option value="lab">Laboratorio</option>
              <option value="equipment">Equipo</option>
            </Select>
          </Field>
          <Field label="Estado">
            <Select value={form.status} onChange={e => setForm(f => ({ ...f, status: e.target.value }))}>
              {Object.entries(STATUS_LABELS).map(([k, v]) => <option key={k} value={k}>{v}</option>)}
            </Select>
          </Field>
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
          <Field label="Ubicación *">
            <Input value={form.location} onChange={e => setForm(f => ({ ...f, location: e.target.value }))} placeholder="Edificio A" />
          </Field>
          <Field label="Capacidad (personas)">
            <Input type="number" value={form.capacity} onChange={e => setForm(f => ({ ...f, capacity: e.target.value }))} placeholder="Ej: 30" />
          </Field>
        </div>
        <Field label="Descripción">
          <Textarea value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} placeholder="Detalles del recurso..." />
        </Field>
      </Modal>

      <Toast {...toast} />
    </div>
  );
}
